#!/usr/bin/env bash
# bin/check-block-standard.sh — Wbcom Block Quality Standard CI gate.
#
# Asserts that every `src/Blocks/<slug>/block.json` declares the
# canonical standard attribute schema. Fails the build if a block is
# missing required keys (uniqueId, padding, margin, hideOnDesktop, etc.)
# so a future PR can't ship a regression to the pre-standard layout.
#
# Run via: bash bin/check-block-standard.sh
#
# Generated by Phase E of the Wbcom Block Quality Standard migration.

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PLUGIN_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"
BLOCKS_DIR="$PLUGIN_DIR/src/Blocks"

if [ ! -d "$BLOCKS_DIR" ]; then
  echo "✗ src/Blocks/ missing — has the standard migration regressed?"
  exit 1
fi

REQUIRED_ATTRS=(
  uniqueId
  padding
  paddingTablet
  paddingMobile
  margin
  marginTablet
  marginMobile
  borderRadius
  hideOnDesktop
  hideOnTablet
  hideOnMobile
  boxShadow
  shadowHorizontal
  shadowVertical
  shadowBlur
  shadowSpread
  shadowColor
)

FAILED=0
CHECKED=0

for block_dir in "$BLOCKS_DIR"/*/; do
  manifest="${block_dir}block.json"
  if [ ! -f "$manifest" ]; then
    continue
  fi

  slug="$(basename "$block_dir")"
  CHECKED=$((CHECKED + 1))

  for attr in "${REQUIRED_ATTRS[@]}"; do
    if ! jq -e --arg key "$attr" '.attributes[$key]' "$manifest" >/dev/null 2>&1; then
      echo "✗ $slug — block.json missing required standard attribute: $attr"
      FAILED=1
    fi
  done

  if ! jq -e '.apiVersion' "$manifest" >/dev/null 2>&1; then
    echo "✗ $slug — block.json missing apiVersion"
    FAILED=1
  else
    api_ver="$(jq -r '.apiVersion' "$manifest")"
    if [ "$api_ver" != "3" ]; then
      echo "✗ $slug — block.json apiVersion=$api_ver (expected 3)"
      FAILED=1
    fi
  fi
done

if [ "$CHECKED" -eq 0 ]; then
  echo "✗ No block.json files found under src/Blocks/"
  exit 1
fi

if [ "$FAILED" -ne 0 ]; then
  echo ""
  echo "Wbcom Block Quality Standard check — FAILED ($CHECKED block(s) inspected)"
  exit 1
fi

echo "Wbcom Block Quality Standard check — green ($CHECKED block(s) compliant)"
exit 0
